module RefModule(
  input clk,
  input reset,
  input data,
  output reg match
);parameter SEARCHING = 2'b00;
  parameter DETECTING = 2'b01;

  reg [1:0] pipeline_reg;
  reg [3:0] shift_reg;

  always @(posedge clk) begin
    if (reset) begin
      pipeline_reg <= SEARCHING;
      shift_reg <= 4'b0;
      match <= 0;
    end else begin
      case (pipeline_reg)
        SEARCHING: begin
          if (data == 1) begin
            pipeline_reg <= DETECTING;
            shift_reg <= {data, shift_reg[3:1]};
          end
        end
        DETECTING: begin
          shift_reg <= {data, shift_reg[3:1]};
          if (shift_reg == 4'b1010) begin
            match <= 1;
            pipeline_reg <= SEARCHING;
          end else if (shift_reg[0] == 0) begin
            pipeline_reg <= SEARCHING;
          end
        end
      endcase
    end
  end

endmodule
